from functools import lru_cache

def solve():
    low = sys.stdin.readline().strip().strip('"')
    high = sys.stdin.readline().strip().strip('"')
    MOD = 10**9 + 7

    def count(num_str):
        n = len(num_str)

        @lru_cache(maxsize=None)
        def dp(pos, last_digit, tight, started):
            if pos == n:
                return 1 if started else 0
            limit = int(num_str[pos]) if tight else 9
            result = 0
            for d in range(0, limit + 1):
                new_tight = tight and (d == limit)
                if not started:
                    if d == 0:
                        result += dp(pos + 1, -1, False, False)
                    else:
                        result += dp(pos + 1, d, new_tight, True)
                else:
                    if last_digit == -1 or abs(d - last_digit) == 1:
                        result += dp(pos + 1, d, new_tight, True)
                result %= MOD
            return result % MOD

        return dp(0, -1, True, False)

    def subtract_one(s):
        digits = list(s)
        i = len(digits) - 1
        while i >= 0 and digits[i] == '0':
            digits[i] = '9'
            i -= 1
        if i >= 0:
            digits[i] = str(int(digits[i]) - 1)
        result = ''.join(digits).lstrip('0')
        return result if result else '0'

