def main():
    data = sys.stdin.read().split('\n')
    coins = json.loads(data[0].strip())
    k = int(data[1].strip())

    # Kth smallest positive integer that is a multiple of at least one coin
    # Inclusion-exclusion with binary search
    n = len(coins)

    def lcm(a, b):
        return a * b // gcd(a, b)

    def count_le(x):
        # Count numbers <= x divisible by at least one coin
        total = 0
        for mask in range(1, 1 << n):
            bits = []
            for i in range(n):
                if mask & (1 << i): bits.append(coins[i])
            l = bits[0]
            for b in bits[1:]:
                l = lcm(l, b)
                if l > x: break
            if l <= x:
                cnt = x // l
                if len(bits) % 2 == 1:
                    total += cnt
                else:
                    total -= cnt
        return total

    lo, hi = 1, k * min(coins)
    while lo < hi:
        mid = (lo + hi) // 2
        if count_le(mid) >= k:
            hi = mid
        else:
            lo = mid + 1
    print(lo)
