def main():
    nums = json.loads(sys.stdin.readline().strip())
    n = len(nums)

    # For each unique value x, compute max subarray sum of nums with all x's removed.
    # O(n * distinct_values) approach.

    from collections import Counter
    cnt = Counter(nums)

    # Base case: no removal. Kadane's.
    def kadane(arr):
        if not arr:
            return float('-inf')
        best = cur = arr[0]
        for i in range(1, len(arr)):
            cur = max(arr[i], cur + arr[i])
            best = max(best, cur)
        return best

    best = kadane(nums)

    # For each unique value, remove it and compute max subarray sum.
    # But we need to handle "subarray" = contiguous in the REMAINING array.
    # After removing all x's, the array is concatenated segments between x positions.
    # Max subarray sum = max subarray sum using modified Kadane's that skips x's.

    for x in cnt:
        if cnt[x] == n:
            continue  # can't remove if it empties the array
        # Kadane's skipping x
        cur = None
        mx = float('-inf')
        for v in nums:
            if v == x:
                continue
            if cur is None or cur < 0:
                cur = v
            else:
                cur += v
            mx = max(mx, cur)
        if mx > float('-inf'):
            best = max(best, mx)

    print(best)

